import{_ as a,o as t,c as i,ak as s}from"./chunks/framework.DiS-pR0X.js";const u=JSON.parse('{"title":"5. Resumen IPv6","description":"","frontmatter":{"title":"5. Resumen IPv6","parent":"IPv6"},"headers":[],"relativePath":"redes/ipv6/resumen.md","filePath":"redes/ipv6/resumen.md","lastUpdated":1775585594000}'),d={name:"redes/ipv6/resumen.md"};function o(n,e,r,c,l,h){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="🌐-ipv6-aspectos-destacados" tabindex="-1">🌐 IPv6: Aspectos destacados <a class="header-anchor" href="#🌐-ipv6-aspectos-destacados" aria-label="Permalink to “🌐 IPv6: Aspectos destacados”">​</a></h1><h2 id="🔧-¿que-es-ipv6" tabindex="-1">🔧 ¿Qué es IPv6? <a class="header-anchor" href="#🔧-¿que-es-ipv6" aria-label="Permalink to “🔧 ¿Qué es IPv6?”">​</a></h2><p>IPv6 (Internet Protocol version 6) es la versión más reciente del protocolo IP. Fue diseñado para reemplazar a IPv4 debido a la escasez de direcciones.</p><hr><h2 id="📏-longitud-y-formato" tabindex="-1">📏 Longitud y formato <a class="header-anchor" href="#📏-longitud-y-formato" aria-label="Permalink to “📏 Longitud y formato”">​</a></h2><ul><li><strong>Tamaño</strong>: 128 bits → permite <strong>2¹²⁸ direcciones únicas</strong></li><li><strong>Formato</strong>: 8 grupos (hextetos) de 4 dígitos hexadecimales, separados por dos puntos <code>:</code></li></ul><p><strong>Ejemplo completo:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2001:0db8:85a3:0000:0000:8a2e:0370:7334</span></span></code></pre></div><p><strong>Forma abreviada:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>2001:db8:85a3::8a2e:370:7334</span></span></code></pre></div><hr><h2 id="🧭-tipos-de-direcciones-ipv6" tabindex="-1">🧭 Tipos de direcciones IPv6 <a class="header-anchor" href="#🧭-tipos-de-direcciones-ipv6" aria-label="Permalink to “🧭 Tipos de direcciones IPv6”">​</a></h2><p>IPv6 no usa broadcast. Se clasifica en:</p><table tabindex="0"><thead><tr><th>Tipo</th><th>Comienza con...</th><th>Alcance</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Unicast</strong></td><td>Varía</td><td>1 a 1</td><td>Identifica un único dispositivo</td></tr><tr><td><strong>Multicast</strong></td><td><code>FF00::/8</code></td><td>1 a varios</td><td>Envío a múltiples destinos</td></tr><tr><td><strong>Anycast</strong></td><td>Igual que unicast</td><td>1 a uno cercano</td><td>Enrutado al nodo más cercano</td></tr></tbody></table><hr><h2 id="🧱-subtipos-de-direcciones-unicast" tabindex="-1">🧱 Subtipos de direcciones Unicast <a class="header-anchor" href="#🧱-subtipos-de-direcciones-unicast" aria-label="Permalink to “🧱 Subtipos de direcciones Unicast”">​</a></h2><table tabindex="0"><thead><tr><th>Subtipo</th><th>Prefijo</th><th>Descripción</th></tr></thead><tbody><tr><td>Global Unicast</td><td><code>2000::/3</code></td><td>Direcciones públicas</td></tr><tr><td>Link-local</td><td><code>fe80::/10</code></td><td>Comunicación en el mismo enlace</td></tr><tr><td>Unique local (ULA)</td><td><code>fc00::/7</code></td><td>Equivalente a redes privadas IPv4</td></tr><tr><td>Loopback</td><td><code>::1</code></td><td>Prueba interna del host</td></tr><tr><td>Unspecified</td><td><code>::</code></td><td>Sin dirección asignada</td></tr></tbody></table><hr><h2 id="🧑‍🔧-asignacion-y-configuracion" tabindex="-1">🧑‍🔧 Asignación y configuración <a class="header-anchor" href="#🧑‍🔧-asignacion-y-configuracion" aria-label="Permalink to “🧑‍🔧 Asignación y configuración”">​</a></h2><ul><li>Manual (estática)</li><li>SLAAC (autoconfiguración sin estado)</li><li>DHCPv6 (versión de DHCP para IPv6)</li></ul><hr><h2 id="🧩-¿como-se-agrupan" tabindex="-1">🧩 ¿Cómo se agrupan? <a class="header-anchor" href="#🧩-¿como-se-agrupan" aria-label="Permalink to “🧩 ¿Cómo se agrupan?”">​</a></h2><ul><li>Las redes IPv6 usan prefijos, como <code>2001:db8::/64</code></li><li>Normalmente se usan subredes <code>/64</code></li><li>Se crean jerarquías: global → subred → host</li></ul><hr><h2 id="✅-ventajas-destacadas" tabindex="-1">✅ Ventajas destacadas <a class="header-anchor" href="#✅-ventajas-destacadas" aria-label="Permalink to “✅ Ventajas destacadas”">​</a></h2><ul><li>🌐 Espacio de direcciones masivo</li><li>🔐 Seguridad integrada con IPSec</li><li>⚡ Elimina la necesidad de NAT</li><li>🤝 Autoconfiguración sencilla (SLAAC)</li><li>🚫 Sin broadcast (menos congestión)</li><li>🛰 Mejor enrutamiento y simplicidad</li></ul><hr>',27)])])}const g=a(d,[["render",o]]);export{u as __pageData,g as default};
